code = """import json
import os

# Get the funding data for FEMA/emergency projects
funding_data = locals()['var_functions.query_db:62']

# Get civic document text - try reading the file
import json
civic_text = ""
civic_docs = locals().get('var_functions.query_db:51', [])

if civic_docs and len(civic_docs) > 0:
    civic_text = civic_docs[0].get('text', '')

# Function to determine project status from text
def get_status(text, project_name):
    if not text:
        return "status not available"
    
    # Get base name without suffix
    base_name = project_name.split('(')[0].strip()
    
    # Convert to lowercase for searching
    text_lower = text.lower()
    base_name_lower = base_name.lower()
    
    # Find the section about this project
    lines = text_lower.split('\n')
    project_context = ""
    
    for i, line in enumerate(lines):
        if base_name_lower in line:
            # Get context around the project mention
            start = max(0, i-5)
            end = min(len(lines), i+10)
            project_context = ' '.join(lines[start:end])
            break
    
    if not project_context:
        return "status not available"
    
    # Check for status keywords
    status_indicators = {
        'completed': ['completed', 'notice of completion', 'construction was completed'],
        'design': ['design', 'planning', 'working with consultant', 'finalize', 'preliminary design'],
        'construction': ['construction', 'under construction', 'begin construction', 'advertise'],
        'not started': ['not started', 'identified', 'application submitted', 'waiting for', 'pending']
    }
    
    for status, keywords in status_indicators.items():
        if any(keyword in project_context for keyword in keywords):
            return status
    
    return "in progress"

# Process each project
results = []
for project in funding_data:
    project_name = project['Project_Name']
    amount = int(project['Amount'])
    
    # Get status from civic documents
    status = get_status(civic_text, project_name)
    
    results.append({
        'project_name': project_name,
        'funding_source': project['Funding_Source'],
        'amount': f"${amount:,}",
        'status': status
    })

# Format output
output = []
output.append("Project Names, Funding Sources, Amounts, and Statuses for 'emergency' or 'FEMA' Related Projects:")
output.append("=" * 100)

for r in results:
    output.append(f"Project: {r['project_name']}")
    output.append(f"  Funding Source: {r['funding_source']}")
    output.append(f"  Amount: {r['amount']}")
    output.append(f"  Status: {r['status']}")
    output.append("")

print('__RESULT__:')
print('\n'.join(output))"""

